  "glossary": [
    {
      "term": "Артефакт",
      "definition": "Именованный результат урока, который можно применить отдельно от учебного текста: функция, SQL-модель, контракт, тестовый набор, отчет, CLI, prompt или skill."
    },
    {
      "term": "Grain",
      "definition": "То, что представляет одна строка таблицы. Grain определяет допустимые ключи, дубликаты, агрегации и объединения."
    },
    {
      "term": "Инвариант",
      "definition": "Условие, которое должно оставаться истинным для корректных входов и результатов расчета."
    },
    {
      "term": "Leakage",
      "definition": "Использование информации, которая не должна быть доступна в момент оценки или принятия решения. Временная, целевая и train/test-утечки дают завышенные результаты."
    },
    {
      "term": "Воспроизводимость",
      "definition": "Возможность получить тот же проверяемый результат из зафиксированных кода, данных, конфигурации и зависимостей."
    },
    {
      "term": "Baseline",
      "definition": "Простое, честное и воспроизводимое решение, с которым сравнивается более сложный метод."
    },
    {
      "term": "Data contract",
      "definition": "Явное соглашение о схеме, grain, ключах, допустимых значениях и качестве набора данных."
    }
  ],
